module.exports = function(options) {
  var id, key, nuc, scope, values;
  key = options.args[0];
  if (key == null) {
    return {
      error: 'Must specify <key> for get command'
    };
  }
  id = options.id;
  scope = options.args[1];
  nuc = require('../lib');
  values = nuc({
    id: id,
    scope: scope
  });
  (function() {
    var header;
    header = 'app @' + id;
    if (scope != null) {
      header += ' in scope ' + scope;
    }
    return console.log(header);
  })();
  return console.log(' ', key, '=', values[key]);
};
